/**
 * Zone Module Service
 *
 * Business logic service for the Zone module.
 * Handles zone CRUD and table grouping operations.
 *
 * @module modules/order/zone.service
 *
 * @example
 * ```typescript
 * import { ZoneService } from '@/modules/order/zone.service';
 * import { resolve } from '@/core/kernel/container';
 *
 * const zoneService = resolve<ZoneService>('ZoneService');
 *
 * // Create a new zone
 * const result = await zoneService.create('org_123', {
 *   name: 'Garden',
 *   color: '#4CAF50',
 * });
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { PrismaClient, Prisma } from '@prisma/client';

import { TOKENS } from '@/core/kernel/container';
import { AppException } from '@/core/exceptions/app.exception';
import { EventService } from '@/core/services/event.service';

import type {
  Zone,
  ZoneWithRelations,
  CreateZoneRequest,
  UpdateZoneRequest,
  ListZonesQuery,
} from '@/modules/order/order.types';

import {
  createZoneSchema,
  updateZoneSchema,
  listZonesQuerySchema,
  type CreateZoneInput,
  type UpdateZoneInput,
  type ListZonesQueryInput,
} from '@/modules/order/order.schema';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * Paginated result type
 */
export interface PaginatedResult<T> {
  /** Array of entities */
  data: T[];
  /** Pagination metadata */
  meta: {
    page: number;
    perPage: number;
    total: number;
    totalPages: number;
  };
}

/**
 * Zone summary for list displays
 */
export interface ZoneSummary {
  /** Zone ID */
  id: string;
  /** Zone name */
  name: string;
  /** Zone color */
  color: string | null;
  /** Sort order */
  sortOrder: number;
  /** Table count */
  tableCount: number;
}

/**
 * User context for operations
 */
interface UserContext {
  /** User ID making the request */
  userId?: string;
  /** Whether user is a platform admin */
  isPlatformAdmin?: boolean;
}

/**
 * Create zone response
 */
export interface CreateZoneResponse {
  /** Created zone */
  zone: Zone;
  /** Response message */
  message: string;
}

/**
 * Update zone response
 */
export interface UpdateZoneResponse {
  /** Updated zone */
  zone: Zone;
  /** Response message */
  message: string;
}

/**
 * Reorder zones response
 */
export interface ReorderZonesResponse {
  /** Reordered zone count */
  count: number;
  /** Response message */
  message: string;
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

const DEFAULT_PER_PAGE = 50;
const MAX_PER_PAGE = 100;

// -----------------------------------------------------------------------------
// Zone Service
// -----------------------------------------------------------------------------

/**
 * Zone module business logic service.
 *
 * Handles all zone-related business operations including:
 * - Zone CRUD operations with tenant isolation
 * - Table grouping
 * - Zone reordering
 * - Event emission
 *
 * @remarks
 * Zone entity does NOT have soft delete (deletedAt).
 * Zones are deleted permanently but only if they have no tables.
 *
 * @example
 * ```typescript
 * @injectable()
 * class SomeController {
 *   constructor(
 *     @inject('ZoneService') private zoneService: ZoneService,
 *   ) {}
 *
 *   async handleCreate(req: Request, res: Response) {
 *     const result = await this.zoneService.create(req.orgId, req.body);
 *     res.json(result);
 *   }
 * }
 * ```
 */
@injectable()
export class ZoneService {
  constructor(
    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient,
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Lists zones for an organization with pagination and filtering.
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param params - Query parameters
   * @returns Paginated list of zones
   *
   * @example
   * ```typescript
   * const result = await zoneService.list('org_123', {
   *   page: 1,
   *   perPage: 50,
   * });
   * ```
   */
  async list(
    organizationId: string,
    params: ListZonesQuery
  ): Promise<PaginatedResult<Zone>> {
    const validated = this.validateInput(params, listZonesQuerySchema) as ListZonesQueryInput;

    const { search, page = 1, perPage = DEFAULT_PER_PAGE } = validated;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where: Prisma.ZoneWhereInput = {
      organizationId,
      ...(search && {
        name: { contains: search, mode: 'insensitive' },
      }),
    };

    // Execute count and find in parallel
    const [total, data] = await Promise.all([
      this.prisma.zone.count({ where }),
      this.prisma.zone.findMany({
        where,
        orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data: data as Zone[],
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Lists all zones for an organization (no pagination).
   *
   * @param organizationId - Organization ID
   * @returns Array of zones
   */
  async listAll(organizationId: string): Promise<Zone[]> {
    const zones = await this.prisma.zone.findMany({
      where: { organizationId },
      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
    });

    return zones as Zone[];
  }

  /**
   * Lists zone summaries (for dropdowns, etc.).
   *
   * @param organizationId - Organization ID
   * @returns Array of zone summaries
   */
  async listSummaries(organizationId: string): Promise<ZoneSummary[]> {
    const zones = await this.prisma.zone.findMany({
      where: { organizationId },
      select: {
        id: true,
        name: true,
        color: true,
        sortOrder: true,
        _count: {
          select: {
            tables: {
              where: { deletedAt: null },
            },
          },
        },
      },
      orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
    });

    return zones.map((zone) => ({
      id: zone.id,
      name: zone.name,
      color: zone.color,
      sortOrder: zone.sortOrder,
      tableCount: zone._count.tables,
    }));
  }

  /**
   * Gets a zone by ID.
   *
   * @param organizationId - Organization ID
   * @param id - Zone ID
   * @returns Zone or null
   */
  async getById(organizationId: string, id: string): Promise<Zone | null> {
    const zone = await this.prisma.zone.findFirst({
      where: { id, organizationId },
    });

    return zone as Zone | null;
  }

  /**
   * Gets a zone by ID with relations.
   *
   * @param organizationId - Organization ID
   * @param id - Zone ID
   * @param includeTables - Include tables in response
   * @returns Zone with relations
   * @throws {AppException} If not found
   */
  async getByIdWithRelations(
    organizationId: string,
    id: string,
    includeTables = false
  ): Promise<ZoneWithRelations> {
    const zone = await this.prisma.zone.findFirst({
      where: { id, organizationId },
      include: {
        ...(includeTables && {
          tables: {
            where: { deletedAt: null },
            orderBy: [{ sortOrder: 'asc' }, { number: 'asc' }],
          },
        }),
      },
    });

    if (!zone) {
      throw AppException.notFound('Zone', id);
    }

    return zone as ZoneWithRelations;
  }

  /**
   * Gets a zone by ID or throws.
   *
   * @param organizationId - Organization ID
   * @param id - Zone ID
   * @returns Zone
   * @throws {AppException} If not found
   */
  async getByIdOrThrow(organizationId: string, id: string): Promise<Zone> {
    const zone = await this.getById(organizationId, id);

    if (!zone) {
      throw AppException.notFound('Zone', id);
    }

    return zone;
  }

  /**
   * Gets a zone by name.
   *
   * @param organizationId - Organization ID
   * @param name - Zone name
   * @returns Zone or null
   */
  async getByName(organizationId: string, name: string): Promise<Zone | null> {
    const zone = await this.prisma.zone.findFirst({
      where: { organizationId, name },
    });

    return zone as Zone | null;
  }

  /**
   * Checks if a zone name exists.
   *
   * @param organizationId - Organization ID
   * @param name - Zone name
   * @param excludeId - Optional ID to exclude
   * @returns True if name exists
   */
  async nameExists(
    organizationId: string,
    name: string,
    excludeId?: string
  ): Promise<boolean> {
    const count = await this.prisma.zone.count({
      where: {
        organizationId,
        name,
        ...(excludeId && { id: { not: excludeId } }),
      },
    });

    return count > 0;
  }

  /**
   * Counts zones for an organization.
   *
   * @param organizationId - Organization ID
   * @returns Count
   */
  async count(organizationId: string): Promise<number> {
    return this.prisma.zone.count({
      where: { organizationId },
    });
  }

  /**
   * Counts tables in a zone.
   *
   * @param organizationId - Organization ID
   * @param zoneId - Zone ID
   * @returns Count of tables
   */
  async countTables(organizationId: string, zoneId: string): Promise<number> {
    return this.prisma.table.count({
      where: {
        organizationId,
        zoneId,
        deletedAt: null,
      },
    });
  }

  // ---------------------------------------------------------------------------
  // Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new zone.
   *
   * Validates input, checks name uniqueness, creates zone,
   * and emits creation event.
   *
   * @param organizationId - Organization ID
   * @param data - Create request data
   * @param context - User context
   * @returns Created zone response
   * @throws {AppException} If zone name already exists
   *
   * @example
   * ```typescript
   * const result = await zoneService.create('org_123', {
   *   name: 'Garden',
   *   color: '#4CAF50',
   * });
   * console.log('Created:', result.zone.id);
   * ```
   */
  async create(
    organizationId: string,
    data: CreateZoneRequest,
    context?: UserContext
  ): Promise<CreateZoneResponse> {
    // Validate input
    const validated = this.validateInput(data, createZoneSchema) as CreateZoneInput;

    // Check if zone name already exists
    if (await this.nameExists(organizationId, validated.name)) {
      throw AppException.alreadyExists('Zone name', validated.name);
    }

    // Create zone
    const zone = await this.prisma.zone.create({
      data: {
        organizationId,
        name: validated.name,
        color: validated.color || null,
        sortOrder: validated.sortOrder ?? 0,
      },
    });

    // Emit creation event
    await this.eventService.emitCustom('zone.created', {
      zoneId: zone.id,
      zoneName: zone.name,
      organizationId,
      createdBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      zone: zone as Zone,
      message: 'Zone created successfully.',
    };
  }

  /**
   * Updates a zone.
   *
   * @param organizationId - Organization ID
   * @param id - Zone ID
   * @param data - Update request data
   * @param context - User context
   * @returns Updated zone response
   * @throws {AppException} If not found or name conflicts
   */
  async update(
    organizationId: string,
    id: string,
    data: UpdateZoneRequest,
    context?: UserContext
  ): Promise<UpdateZoneResponse> {
    // Validate input
    const validated = this.validateInput(data, updateZoneSchema) as UpdateZoneInput;

    // Get current zone
    const current = await this.getByIdOrThrow(organizationId, id);

    // Check name uniqueness if changing
    if (validated.name && validated.name !== current.name) {
      if (await this.nameExists(organizationId, validated.name, id)) {
        throw AppException.alreadyExists('Zone name', validated.name);
      }
    }

    // Build update data
    const updateData: Prisma.ZoneUpdateInput = {};
    if (validated.name !== undefined) updateData.name = validated.name;
    if (validated.color !== undefined) updateData.color = validated.color;
    if (validated.sortOrder !== undefined) updateData.sortOrder = validated.sortOrder;

    // Update zone
    const zone = await this.prisma.zone.update({
      where: { id },
      data: updateData,
    });

    // Emit update event
    await this.eventService.emitCustom('zone.updated', {
      zoneId: zone.id,
      zoneName: zone.name,
      organizationId,
      changes: updateData,
      updatedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      zone: zone as Zone,
      message: 'Zone updated successfully.',
    };
  }

  /**
   * Reorders zones.
   *
   * @param organizationId - Organization ID
   * @param items - Array of ID and sortOrder pairs
   * @param context - User context
   * @returns Reorder response
   */
  async reorder(
    organizationId: string,
    items: Array<{ id: string; sortOrder: number }>,
    context?: UserContext
  ): Promise<ReorderZonesResponse> {
    // Verify all zones exist and belong to the organization
    const zoneIds = items.map((item) => item.id);
    const existingCount = await this.prisma.zone.count({
      where: {
        id: { in: zoneIds },
        organizationId,
      },
    });

    if (existingCount !== zoneIds.length) {
      throw new AppException('INVALID_ZONES', 400, {
        message: 'Some zones do not exist or do not belong to this organization',
      });
    }

    // Update sort orders in transaction
    await this.prisma.$transaction(
      items.map((item) =>
        this.prisma.zone.update({
          where: { id: item.id },
          data: { sortOrder: item.sortOrder },
        })
      )
    );

    await this.eventService.emitCustom('zone.reordered', {
      organizationId,
      items,
      reorderedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      count: items.length,
      message: 'Zones reordered successfully.',
    };
  }

  // ---------------------------------------------------------------------------
  // Delete Operations
  // ---------------------------------------------------------------------------

  /**
   * Deletes a zone permanently.
   *
   * @remarks
   * Zone entity does not have soft delete. Deletion is permanent
   * but only allowed if the zone has no tables assigned.
   *
   * @param organizationId - Organization ID
   * @param id - Zone ID
   * @param context - User context
   * @throws {AppException} If not found or has tables
   *
   * @example
   * ```typescript
   * await zoneService.delete('org_123', 'zone_456');
   * ```
   */
  async delete(organizationId: string, id: string, context?: UserContext): Promise<void> {
    const zone = await this.getByIdOrThrow(organizationId, id);

    // Check if has tables
    const tableCount = await this.countTables(organizationId, id);
    if (tableCount > 0) {
      throw new AppException('ZONE_HAS_TABLES', 400, {
        message: 'Cannot delete zone with tables. Move or delete tables first.',
        tableCount,
      });
    }

    // Delete permanently (Zone doesn't have soft delete)
    await this.prisma.zone.delete({
      where: { id },
    });

    // Emit deletion event
    await this.eventService.emitCustom('zone.deleted', {
      zoneId: zone.id,
      zoneName: zone.name,
      organizationId,
      deletedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });
  }

  // ---------------------------------------------------------------------------
  // Validation Operations
  // ---------------------------------------------------------------------------

  /**
   * Checks if a zone name is available.
   *
   * @param organizationId - Organization ID
   * @param name - Zone name to check
   * @param excludeId - Optional ID to exclude
   * @returns True if available
   */
  async isNameAvailable(
    organizationId: string,
    name: string,
    excludeId?: string
  ): Promise<boolean> {
    return !(await this.nameExists(organizationId, name, excludeId));
  }

  // ---------------------------------------------------------------------------
  // Helper Methods
  // ---------------------------------------------------------------------------

  /**
   * Validates input data against a Zod schema.
   */
  private validateInput<T>(data: unknown, schema: { parse: (data: unknown) => T }): T {
    try {
      return schema.parse(data);
    } catch (error) {
      if (error && typeof error === 'object' && 'errors' in error) {
        const zodError = error as { errors: Array<{ path: string[]; message: string; code: string }> };
        const validationErrors = zodError.errors.map((err) => ({
          field: err.path.join('.'),
          message: err.message,
          rule: err.code,
        }));
        throw AppException.validation(validationErrors);
      }
      throw error;
    }
  }
}
